  note += "`<<PARALLEL_DELEGATE:task_id|specialist_name|goal prompt>>`пјҲе–®иЎҢпјүвҖ” дёҰиЎҢе§”жҙҫеӨҡеҖӢд»»еӢҷзөҰ specialistгҖӮ\n";
