    "name=kebab-caseвүӨ60пјҲе°ҮжҲҗзӮә ms-{name}/ иіҮж–ҷеӨҫеҗҚпјүпјӣreasonвүӨ500 иӘӘжҳҺзӮәдҪ•еҖјеҫ—гҖӮ\n" +
    "Bridge зҷјзўәиӘҚжҢүйҲ•пјҢдҪҝз”ЁиҖ…еҗҢж„ҸжүҚиҗғеҸ–гҖӮеғ…еңЁзҷјзҸҫеҸҜи·Ёе°ҲжЎҲйҮҚз”Ёзҡ„жЁЎејҸжҷӮеҠ пјҢдёҖеүҮиҮіеӨҡ1еҖӢгҖӮ\n" +
    "[End tool]\n\n";
  const continueNote =
    "[Telegram bridge tool: continue]\n" +
    "`<<CONTINUE>>`пјҲе–®иЎҢпјүвҖ” е‘ҠиЁҙ bridge дҪ йӮ„жІ’еҒҡе®ҢпјҢйңҖиҰҒеҶҚдёҖијӘгҖӮ\n" +
    "Bridge ж”¶еҲ°еҫҢиҮӘеӢ•жҺ’зЁӢдёӢдёҖеҖӢ turnпјҢдёҚйңҖдҪҝз”ЁиҖ…д»Ӣе…ҘгҖӮ\n" +
    "дҪҝз”ЁжҷӮж©ҹпјҡе–®ж¬ЎеӣһиҰҶеҒҡдёҚе®ҢпјҲtool call еӨӘеӨҡгҖҒиҰҒж”№еӨҡеҖӢжӘ”жЎҲгҖҒеӨҡжӯҘй©ҹд»»еӢҷпјүгҖӮ\n" +
    "йҷҗеҲ¶пјҡ/goal е•ҹеӢ•жҷӮдёҚйңҖиҰҒз”ЁпјҲgoal зі»зөұиҮӘеё¶ continuationпјүпјӣдёҖеүҮеҸӘиӘҚдёҖеҖӢгҖӮ\n" +
    "[End tool]\n\n";
  const relayDelegateNote = config.relay
    ? buildRelayDelegateNote()
    : "";
  const specialistProxyNote = buildSpecialistProxyNote();
  const parallelDelegateNote = buildParallelDelegateNote();
  const memoryBlock = buildMemoryBlock(facts, {
    tail: tailOverride ?? config.memoryPreambleTail,
    topics: config.memoryPreambleTopics,
    userId,
    compressed,
  });
  const dailylogBlock = buildDailylogBlock();
  const wikiBlock = buildWikiIndexBlock();
  const indexBlock = buildIndexBlock();
  const envBlock = buildEnvironmentBlock(userId, agentCommand);
  const scriptsBlock = buildScriptsBlock();
