  const rtkNote = config.rtkShellRewrite
    ? "[Shell optimization: RTK]\n" +
      "rtk (Rust Token Killer) is installed. When using the shell tool, prefix commands with `rtk` for compressed output:\n" +
      "  `rtk git status` / `rtk git diff` / `rtk git log` вҖ” compact git output\n" +
      "  `rtk read <file>` / `rtk read <file> -l aggressive` вҖ” signatures only\n" +
      "  `rtk grep <pattern> .` вҖ” grouped search results\n" +
      "  `rtk cargo test` / `rtk npm test` вҖ” failures only\n" +
      "Do NOT prefix: interactive commands, piped chains, or commands where full output is needed.\n" +
      "[End RTK]\n\n"
    : "";
  return {
    sendFileNote,
    askNote,
    scheduleNote,
    skillUsedNote,
    goalDoneNote,
    restartNote,
    stickerNote,
    wikiQueryNote,
    skillProposeNote,
    continueNote,
    relayDelegateNote,
    specialistProxyNote,
    parallelDelegateNote,
    rtkNote,
    envBlock,
    memoryBlock,
