/**
 * Environment preamble: tells the agent where this bridge stores memory,
 * skills, agent config files, and which Telegram user owns the session.
 * Skills and long-term notes can reference these as ${MEMORY_DIR},
 * ${SKILL_DIR}, ${AGENT_CONFIG_DIR}, ${USER_ID} rather than hard-coding
 * machine-specific paths вҖ” so the same SKILL.md works on the Kiro box,
 * the Codex box, and the Claude box.
 *
 * Heuristic: agent.command name hints which CLI we're paired with
 * (kiro вҶ’ ~/.kiro, codex вҶ’ ~/.codex, claude вҶ’ ~/.claude). Any of the
 * three variables can be overridden via the matching env var.
 */
/**
 * Build relay delegate tool note from external config file.
 * Reads MEMORY_DIR/config/relay-peers.json (fallback: AGENT_CONFIG_DIR).
 */
function buildRelayDelegateNote(): string {
  interface PeerConfig {
    abilities: string[];
    delegateWhen: string[];
  }
  const cfgPath = resolveBridgeConfigPath("relay-peers.json", detectAgentConfigDir());
  let peers: Record<string, PeerConfig>;
  try {
    peers = JSON.parse(readFileSync(cfgPath, "utf8"));
  } catch {
    console.warn(`[preamble] relay-peers.json not found at ${cfgPath} вҖ” relay delegate tool note disabled`);
    return "";
  }
  const names = Object.keys(peers);
  if (names.length === 0) return "";
  let note = "[Telegram bridge tool: relay delegate]\n";
  note += "`<<RELAY_DELEGATE:<peer>|goal prompt>>`пјҲе–®иЎҢпјүвҖ” е§”жҙҫд»»еӢҷзөҰеҸҰдёҖеҸ°ж©ҹеҷЁдёҠзҡ„ AI agentгҖӮ\n";
  note += "д№ҹжҺҘеҸ— JSON ж јејҸпјҡ`<<RELAY_DELEGATE:<peer>|{\"id\":\"<id>\",\"goal\":\"...\",\"context\":\"...\"}>>`\n";
  note += "зҙ”ж–Үеӯ—жҷӮ bridge иҮӘеӢ•з”ўз”ҹ idгҖӮgoal prompt дёҚеҸҜеҗ« `>>` жҲ– `|`гҖӮ\n";
  note += "Bridge жңғиҮӘеӢ•дҝқеӯҳдҪ зҡ„е·ҘдҪңзӢҖж…ӢпјҢе°Қж–№е®ҢжҲҗеҫҢзөҗжһңйқңй»ҳжіЁе…ҘдҪ зҡ„ sessionгҖӮ\n\n";
  for (const [name, cfg] of Object.entries(peers)) {
    const extra = (cfg as any).note ? `пјҲ${(cfg as any).note}пјү` : "";
    note += `гҖҢ${name}гҖҚ${extra}зҡ„иғҪеҠӣпјҡ\n`;
    for (const a of cfg.abilities) note += `- ${a}\n`;
    note += `\nдҪ•жҷӮе§”жҙҫзөҰгҖҢ${name}гҖҚпјҡ\n`;
    for (const w of cfg.delegateWhen) note += `- ${w}\n`;
    note += "\n";
  }
  note += "ж јејҸиҰҸеүҮпјҡ\n";
  note += "- зҙ”ж–Үеӯ—ж јејҸпјҲжҺЁи–Ұпјүпјҡ`<<RELAY_DELEGATE:peer|д»»еӢҷжҸҸиҝ°>>`\n";
  note += "- JSON ж јејҸпјҲйңҖиҰҒеё¶ context/maxTurns жҷӮпјүпјҡ`<<RELAY_DELEGATE:peer|{\"id\":\"rd_xxx\",\"goal\":\"...\",\"context\":\"...\"}>>` \n";
  note += "- goal/prompt дёҚеҸҜеҗ« `>>` жҲ– `|`\n";
  note += "- goal жҮүеҗ«дә”иҰҒзҙ пјҡ\n";
  note += "  1. зӣ®жЁҷиҲҮеӢ•ж©ҹпјҲзӮәд»Җйәје§”жҙҫпјү\n";
  note += "  2. е·ІзҹҘиғҢжҷҜпјҲдҪ е·ІжҺҢжҸЎзҡ„дәӢеҜҰгҖҒе·Іеҳ—и©Ұзҡ„ж–№жЎҲгҖҒй—ңйҚөиӯүж“ҡвҖ”вҖ”дёҚиҰҒи®“ delegate еҫһйӣ¶й–Ӣе§Ӣпјү\n";
  note += "  3. еҫ…жұәе•ҸйЎҢпјҲе…·й«”иҰҒ delegate еӣһзӯ”жҲ–з”ўеҮәд»Җйәјпјү\n";
  note += "  4. й©—ж”¶жўқд»¶\n";
  note += "  5. еӣһе ұж јејҸпјҲеҸӘеӣһзөҗи«–+жӘ”жЎҲ:иЎҢиҷҹпјҢй•·з”ўзү©еӯҳжӘ”еӣһеӮіи·Ҝеҫ‘пјү\n";
  note += "- зөҗжһңеӣһдҫҶеҫҢпјҡзөҰ delegate зөҗи«–иӘҚзңҹж¬ҠйҮҚпјҲзҚЁз«ӢиҰ–и§’пјүпјӣеғ…еңЁз¶“й©—жҖ§еӨұж•—жҲ–дёҖжүӢиіҮж–ҷзҹӣзӣҫжҷӮжүҚдёҚжҺЎзҙҚпјӣж•ҙеҗҲеҫҢз°ЎиҰҒе‘ҠзҹҘдҪҝз”ЁиҖ…\n";
  note += "- дёҚиҰҒзӯүзөҗжһңвҖ”вҖ”зҷјеҮәеҫҢжӯЈеёёеӣһиҰҶдҪҝз”ЁиҖ…гҖҢе·Іе§”жҙҫгҖҚеҚіеҸҜ\n";
  note += "- вҡ пёҸ йҮҚиҰҒпјҡзҷј RELAY_DELEGATE зҡ„ turn еҝ…й ҲеҢ…еҗ«иҮіе°‘дёҖеҖӢ tool callпјҲеҰӮ list_factsпјүпјҢеҗҰеүҮ token жңғиў« CLI еҗһжҺүдёҚйҖҒеҮә\n";
  note += "[End tool]\n\n";
  return note;
}

function buildSpecialistProxyNote(): string {
  const cfgPath = resolveBridgeConfigPath("specialists.json", detectAgentConfigDir());
  let specs: { name: string; cwd: string }[];
  try {
    specs = JSON.parse(readFileSync(cfgPath, "utf8"));
  } catch {
    return "";
  }
  if (!Array.isArray(specs) || specs.length === 0) return "";
  let note = "[Telegram bridge tool: specialist proxy]\n";
  note += "`<<SPECIALIST_PROXY:name|дҪҝз”ЁиҖ…зҡ„еҺҹе§ӢиЁҠжҒҜ>>`пјҲе–®иЎҢпјүвҖ” жҠҠдҪҝз”ЁиҖ…зҡ„иЁҠжҒҜиҪүдәӨзөҰжң¬ж©ҹ specialist еҚіжҷӮеӣһзӯ”гҖӮ\n";
  note += "йҖІе…Ҙ proxy жЁЎејҸеҫҢпјҢдҪҝз”ЁиҖ…еҫҢзәҢиЁҠжҒҜзӣҙйҖҒ specialistпјҢеӣһиҰҶзӣҙйҖҒдҪҝз”ЁиҖ…пјҢзӣҙеҲ°дҪҝз”ЁиҖ…иӘӘ /backгҖӮ\n";
  note += "Specialist зҡ„иЁҳжҶ¶жңғеӣһжөҒеҲ°дҪ зҡ„ factsгҖӮproxy зөҗжқҹжҷӮдҪ жңғж”¶еҲ°е°Қи©ұж‘ҳиҰҒгҖӮ\n\n";
  note += "еҸҜз”Ё specialistпјҡ\n";
  for (const s of specs) {
    note += `- ${s.name}пјҲе·ҘдҪңзӣ®йҢ„пјҡ${s.cwd}пјү\n`;
  }
  note += "\nдҪҝз”ЁжҷӮж©ҹпјҡдҪҝз”ЁиҖ…зҡ„е•ҸйЎҢжҳҺзўәеұ¬ж–јжҹҗ specialist зҡ„й ҳеҹҹпјҢдё”йңҖиҰҒеҚіжҷӮдә’еӢ•пјҲдёҚжҳҜиғҢжҷҜд»»еӢҷпјүгҖӮ\n";
  note += "иғҢжҷҜд»»еӢҷз”Ё RELAY_DELEGATEпјӣеҚіжҷӮе°Қи©ұз”Ё SPECIALIST_PROXYгҖӮ\n";
  note += "[End tool]\n\n";
  return note;
}

function buildParallelDelegateNote(): string {
  const cfgPath = resolveBridgeConfigPath("specialists.json", detectAgentConfigDir());
  let specs: { name: string }[];
  try {
    specs = JSON.parse(readFileSync(cfgPath, "utf8"));
  } catch {
